#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const MINIGIT_DIR = '.minigit';
const OBJECTS_DIR = path.join(MINIGIT_DIR, 'objects');
const INDEX_FILE = path.join(MINIGIT_DIR, 'index');
const HEAD_FILE = path.join(MINIGIT_DIR, 'HEAD');
const REFS_DIR = path.join(MINIGIT_DIR, 'refs');
const MASTER_REF = path.join(REFS_DIR, 'master');

const args = process.argv.slice(2);
const command = args[0];

function init() {
  if (fs.existsSync(MINIGIT_DIR)) {
    console.error('Initialized empty minigit repository');
    return;
  }
  fs.mkdirSync(MINIGIT_DIR);
  fs.mkdirSync(OBJECTS_DIR);
  fs.mkdirSync(REFS_DIR);
  fs.writeFileSync(HEAD_FILE, 'ref: refs/master\n');
  fs.writeFileSync(INDEX_FILE, '');
  console.log('Initialized empty minigit repository');
}

function hashObject(content) {
  const hash = crypto.createHash('sha1');
  hash.update(content);
  return hash.digest('hex');
}

function writeBlob(content) {
  const hash = hashObject(content);
  const dir = path.join(OBJECTS_DIR, hash.slice(0, 2));
  const file = path.join(dir, hash.slice(2));
  if (!fs.existsSync(dir)) fs.mkdirSync(dir);
  fs.writeFileSync(file, content);
  return hash;
}

function hashObjectCommand(file) {
  if (!fs.existsSync(file)) {
    console.error(`error: could not open ${file} for reading: No such file or directory`);
    process.exit(1);
  }
  const content = fs.readFileSync(file);
  const hash = writeBlob(content);
  process.stdout.write(hash);
}

function catFile(hash) {
  const file = path.join(OBJECTS_DIR, hash.slice(0, 2), hash.slice(2));
  if (!fs.existsSync(file)) {
    console.error('error: object not found');
    process.exit(1);
  }
  const content = fs.readFileSync(file);
  process.stdout.write(content);
}

function lsFiles() {
  if (!fs.existsSync(INDEX_FILE)) return;
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index.split('\n').filter(line => line.length > 0);
  entries.forEach(entry => {
    const [mode, hash, filename] = entry.split(' ');
    console.log(`${mode} ${hash} ${filename}`);
  });
}

function updateIndex(file) {
  if (!fs.existsSync(file)) {
    console.error(`error: could not open ${file} for reading: No such file or directory`);
    process.exit(1);
  }
  const content = fs.readFileSync(file);
  const hash = writeBlob(content);
  const mode = '100644';
  const entry = `${mode} ${hash} ${file}\n`;
  let index = '';
  if (fs.existsSync(INDEX_FILE)) {
    index = fs.readFileSync(INDEX_FILE, 'utf8');
  }
  const lines = index.split('\n').filter(line => line.length > 0);
  const newLines = [];
  let found = false;
  for (const line of lines) {
    const parts = line.split(' ');
    if (parts[2] === file) {
      newLines.push(entry.trim());
      found = true;
    } else {
      newLines.push(line);
    }
  }
  if (!found) {
    newLines.push(entry.trim());
  }
  fs.writeFileSync(INDEX_FILE, newLines.join('\n') + '\n');
}

function writeTree() {
  if (!fs.existsSync(INDEX_FILE)) {
    console.error('error: your repository is empty');
    process.exit(1);
  }
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index.split('\n').filter(line => line.length > 0);
  let tree = '';
  entries.forEach(entry => {
    const [mode, hash, filename] = entry.split(' ');
    tree += `${mode} ${filename}\0${hash}`;
  });
  const hash = writeBlob(tree);
  console.log(hash);
}

function commitTree(tree, parent, message) {
  let content = `tree ${tree}\n`;
  if (parent) {
    content += `parent ${parent}\n`;
  }
  const author = 'Author <author@example.com>';
  const committer = 'Committer <committer@example.com>';
  const timestamp = Math.floor(Date.now() / 1000);
  content += `author ${author} ${timestamp} +0000\n`;
  content += `committer ${committer} ${timestamp} +0000\n\n`;
  content += `${message}\n`;
  const hash = writeBlob(content);
  let head = '';
  if (fs.existsSync(HEAD_FILE)) {
    head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
  }
  if (head.startsWith('ref: ')) {
    const ref = head.slice(5);
    const refFile = path.join(MINIGIT_DIR, ref);
    fs.writeFileSync(refFile, hash);
  } else {
    fs.writeFileSync(HEAD_FILE, hash);
  }
  console.log(hash);
}

function updateRef(ref, hash) {
  const refFile = path.join(MINIGIT_DIR, ref);
  fs.writeFileSync(refFile, hash);
}

function readRef(ref) {
  const refFile = path.join(MINIGIT_DIR, ref);
  if (fs.existsSync(refFile)) {
    return fs.readFileSync(refFile, 'utf8').trim();
  }
  return null;
}

function revParse(ref) {
  if (ref === 'HEAD') {
    if (fs.existsSync(HEAD_FILE)) {
      const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
      if (head.startsWith('ref: ')) {
        const refName = head.slice(5);
        return readRef(refName);
      } else {
        return head;
      }
    }
  }
  return readRef(ref);
}

switch (command) {
  case 'init':
    init();
    break;
  case 'hash-object':
    hashObjectCommand(args[1]);
    break;
  case 'cat-file':
    catFile(args[1]);
    break;
  case 'ls-files':
    lsFiles();
    break;
  case 'update-index':
    updateIndex(args[1]);
    break;
  case 'write-tree':
    writeTree();
    break;
  case 'commit-tree':
    commitTree(args[1], args[2], args[3]);
    break;
  case 'update-ref':
    updateRef(args[1], args[2]);
    break;
  case 'rev-parse':
    const hash = revParse(args[1]);
    if (hash) {
      console.log(hash);
    }
    break;
  default:
    console.error(`error: unknown command ${command}`);
    process.exit(1);
}
